//! kaiju-ppl — native wikitext-style perplexity for a .knot via the same
//! host-driven forward path as `native-pipeline-smoke`, using the standard
//! llama.cpp `perplexity()` convention so the number is comparable to the
//! IQ-ladder baselines (Q4_K 7.689 / IQ3_XXS 8.251 / IQ2_M 8.835 @ ctx=512).
//!
//! CTX WINDOW: the native prefill window is `prefill_capacity()`, which
//! defaults to `BATCH_CAPACITY = 128` but is raisable per-process via
//! `MOONSHINE_BATCH_CAPACITY` (the KV cache already defaults to 8192, so it is
//! not the limiter). Set `MOONSHINE_BATCH_CAPACITY=512` to score at ctx=512 and
//! get a number directly comparable to the llama.cpp ledger (Q4_K 7.689 /
//! IQ3_XXS 8.251 / IQ2_M 8.835, all `llama-perplexity -c 512`). At the default
//! 128 the scored positions see less context and ppl is systematically higher.
//!
//! llama.cpp `perplexity()` replicated exactly:
//!   - tokenize whole corpus (done upstream in Python; we read u32 LE ids)
//!   - non-overlapping chunks of `n_ctx` tokens (stride = n_ctx)
//!   - `first = n_ctx/2`; for each chunk score positions [first, n_ctx-1),
//!     i.e. predict token[start+pos+1] from the logits at position `pos`
//!   - nll += -log_softmax(logits_pos)[target]; count += n_ctx-1-first
//!   - PPL = exp(nll / count)
//!
//! DISTRIBUTIONAL (KL) GATE — the reason this bin exists beyond a ppl number.
//! The argmax gate in `cloudbuild-kaiju-encode.yaml` checks ONE token's top-1;
//! a small-L2 quant can pass argmax while injecting large cross-entropy on the
//! tail (the L2-cannot-bound-KL failure mode). With `--ref-knot <path>` this
//! bin runs BOTH knots on the identical scored positions and accumulates the
//! per-token KL(ref ‖ kaiju) = Σ_v p_ref log(p_ref / p_kaiju) plus each knot's
//! NLL, then emits a machine-readable `[KLGATE]` line. The cloud gate step
//! fails when `mean_kl` (or the requested percentile) exceeds a threshold, so
//! a passes-argmax / fails-distribution knot cannot ship. Reference is any
//! knot of the same model — typically the same-size IQ baseline, which also
//! makes the ppl comparison a direct "beats/matches IQ" verdict.
//!
//! Usage:
//!   kaiju-ppl <knot.path> --tokens-file <ids.u32le> \
//!            [--ctx 128] [--max-chunks N] \
//!            [--ref-knot <ref.knot>] [--kl-max <f64>] [--ppl-slack <f64>]
//!
//! Token file: raw little-endian u32 token ids, no header.

use std::env;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;

/// Per-knot forward dims, read from the knot config (with qwen2.5-7b fallbacks
/// preserved from the original bin so a config-less knot still scores).
struct KnotDims {
    num_layers: usize,
    vocab_size: usize,
    hidden_dim: usize,
}

fn dims_of(knot: &KnotWeights) -> KnotDims {
    KnotDims {
        num_layers: knot.config.as_ref().map(|c| c.num_layers).unwrap_or(28),
        vocab_size: knot.config.as_ref().map(|c| c.vocab_size).unwrap_or(152064),
        hidden_dim: knot.config.as_ref().map(|c| c.hidden_dim).unwrap_or(3584),
    }
}

/// Run one non-overlapping ctx window through the whole model and return the
/// full per-position logits (`seq_len * vocab_size`, row-major by position).
/// Mirrors `native-pipeline-smoke`'s forward exactly; each call re-embeds at
/// position 0 so chunks are independent.
fn chunk_logits(
    pipeline: &mut NativeLlamaPipeline,
    window: &[u32],
    dims: &KnotDims,
) -> Result<Vec<f32>, String> {
    let seq_len = window.len();
    let residual = pipeline.embed_chunk(window, 0)?;
    let mut last_layer_out: Vec<f32> = Vec::new();
    for layer in 0..dims.num_layers {
        let is_first = layer == 0;
        let is_last = layer == dims.num_layers - 1;
        let attn_input: &[f32] = if is_first { &residual[..] } else { &[] };
        pipeline.forward_range_attn_chunk(attn_input, layer, 0, seq_len, is_first)?;
        pipeline.forward_range_ffn_gate_chunk(layer, seq_len)?;
        pipeline.forward_range_ffn_up_chunk(layer, seq_len)?;
        let out = pipeline.forward_range_ffn_down_chunk(layer, seq_len, is_last);
        if is_last {
            last_layer_out = out?;
        }
    }
    pipeline.lm_head_all_positions(&last_layer_out, seq_len)
}

/// Numerically-stable log-softmax value at a single index (returns log p_target).
fn log_softmax_at(row: &[f32], target: usize) -> f64 {
    let mut m = f32::NEG_INFINITY;
    for &v in row {
        if v > m {
            m = v;
        }
    }
    let mut sum = 0.0f64;
    for &v in row {
        sum += ((v - m) as f64).exp();
    }
    (row[target] - m) as f64 - sum.ln()
}

/// KL(p_ref ‖ p_kaiju) for one position from the two logit rows.
/// = Σ_v p_ref(v) · (logp_ref(v) − logp_kaiju(v)). Stable via shared max
/// subtraction per row; only ref's probabilities weight the sum, so tail mass
/// that kaiju gets wrong but ref is confident about is exactly what dominates.
fn kl_ref_kaiju(ref_row: &[f32], kaiju_row: &[f32]) -> f64 {
    debug_assert_eq!(ref_row.len(), kaiju_row.len());
    let mut mr = f32::NEG_INFINITY;
    let mut mk = f32::NEG_INFINITY;
    for &v in ref_row {
        if v > mr {
            mr = v;
        }
    }
    for &v in kaiju_row {
        if v > mk {
            mk = v;
        }
    }
    let mut sr = 0.0f64;
    let mut sk = 0.0f64;
    for &v in ref_row {
        sr += ((v - mr) as f64).exp();
    }
    for &v in kaiju_row {
        sk += ((v - mk) as f64).exp();
    }
    let lsr = sr.ln();
    let lsk = sk.ln();
    let mut kl = 0.0f64;
    for i in 0..ref_row.len() {
        let logp = (ref_row[i] - mr) as f64 - lsr;
        if logp < -40.0 {
            continue; // p_ref ≈ 0 → contributes ~0, skip the exp
        }
        let logq = (kaiju_row[i] - mk) as f64 - lsk;
        let p = logp.exp();
        kl += p * (logp - logq);
    }
    kl.max(0.0)
}

fn main() -> Result<(), String> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 4 {
        return Err(format!(
            "usage: {} <knot.path> --tokens-file <ids.u32le> [--ctx 128] \
             [--max-chunks N] [--ref-knot <ref.knot>] [--kl-max F] [--ppl-slack F]",
            args.first().map(String::as_str).unwrap_or("kaiju-ppl")
        ));
    }
    let knot_path = args[1].clone();
    let mut tokens_file: Option<String> = None;
    let mut n_ctx: usize = 128;
    let mut max_chunks: Option<usize> = None;
    let mut ref_knot_path: Option<String> = None;
    let mut kl_max: Option<f64> = None;
    let mut ppl_slack: Option<f64> = None;
    let mut i = 2;
    while i < args.len() {
        match args[i].as_str() {
            "--tokens-file" => {
                i += 1;
                tokens_file = Some(args.get(i).ok_or("--tokens-file needs a path")?.clone());
            }
            "--ctx" => {
                i += 1;
                n_ctx = args
                    .get(i)
                    .ok_or("--ctx needs a value")?
                    .parse()
                    .map_err(|e| format!("bad --ctx: {e}"))?;
            }
            "--max-chunks" => {
                i += 1;
                max_chunks = Some(
                    args.get(i)
                        .ok_or("--max-chunks needs a value")?
                        .parse()
                        .map_err(|e| format!("bad --max-chunks: {e}"))?,
                );
            }
            "--ref-knot" => {
                i += 1;
                ref_knot_path = Some(args.get(i).ok_or("--ref-knot needs a path")?.clone());
            }
            "--kl-max" => {
                i += 1;
                kl_max = Some(
                    args.get(i)
                        .ok_or("--kl-max needs a value")?
                        .parse()
                        .map_err(|e| format!("bad --kl-max: {e}"))?,
                );
            }
            "--ppl-slack" => {
                i += 1;
                ppl_slack = Some(
                    args.get(i)
                        .ok_or("--ppl-slack needs a value")?
                        .parse()
                        .map_err(|e| format!("bad --ppl-slack: {e}"))?,
                );
            }
            other => return Err(format!("unknown arg {other:?}")),
        }
        i += 1;
    }
    let tokens_file = tokens_file.ok_or("--tokens-file is required")?;

    // Read u32 LE token ids.
    let raw = std::fs::read(&tokens_file).map_err(|e| format!("read tokens: {e}"))?;
    if raw.len() % 4 != 0 {
        return Err(format!("token file len {} not a multiple of 4", raw.len()));
    }
    let all_tokens: Vec<u32> = raw
        .chunks_exact(4)
        .map(|b| u32::from_le_bytes([b[0], b[1], b[2], b[3]]))
        .collect();
    println!("[ppl] loaded {} tokens from {}", all_tokens.len(), tokens_file);

    // Load knot + build pipeline (reused across all windows so the dequant
    // memo cache warms once).
    println!("[ppl] mmap knot: {}", knot_path);
    let t0 = Instant::now();
    let knot = KnotWeights::load(&knot_path)?;
    let dims = dims_of(&knot);
    println!(
        "[ppl] config: layers={} vocab={} hidden={}  (load {} ms)",
        dims.num_layers,
        dims.vocab_size,
        dims.hidden_dim,
        t0.elapsed().as_millis()
    );
    let cap = NativeLlamaPipeline::prefill_capacity();
    if n_ctx > cap {
        eprintln!("[ppl] ctx {n_ctx} exceeds prefill capacity {cap}; clamping to {cap}");
        n_ctx = cap;
    }
    let mut pipeline = NativeLlamaPipeline::from_knot(knot, false, 0.0);

    // Optional reference pipeline for the distributional (KL) gate.
    let mut ref_pipeline: Option<NativeLlamaPipeline> = None;
    if let Some(rp) = &ref_knot_path {
        println!("[ppl] mmap ref knot: {}", rp);
        let rknot = KnotWeights::load(rp)?;
        let rdims = dims_of(&rknot);
        if rdims.vocab_size != dims.vocab_size {
            return Err(format!(
                "ref vocab {} != kaiju vocab {} — KL needs the same tokenizer/head",
                rdims.vocab_size, dims.vocab_size
            ));
        }
        if rdims.num_layers != dims.num_layers {
            eprintln!(
                "[ppl] WARN ref layers {} != kaiju layers {} (different arch?)",
                rdims.num_layers, dims.num_layers
            );
        }
        ref_pipeline = Some(NativeLlamaPipeline::from_knot(rknot, false, 0.0));
    }

    let vocab_size = dims.vocab_size;
    let first = n_ctx / 2;
    let per_chunk = n_ctx - first - 1; // scored predictions per chunk
    let n_chunk_max = all_tokens.len() / n_ctx;
    let n_chunk = max_chunks.map(|m| m.min(n_chunk_max)).unwrap_or(n_chunk_max);
    if n_chunk == 0 {
        return Err(format!(
            "need >= {} tokens for one ctx={} chunk; have {}",
            n_ctx,
            n_ctx,
            all_tokens.len()
        ));
    }
    println!(
        "[ppl] ctx={} first={} per_chunk_scored={} chunks={} (max_available={}) ref={}",
        n_ctx,
        first,
        per_chunk,
        n_chunk,
        n_chunk_max,
        ref_knot_path.as_deref().unwrap_or("<none>")
    );

    let mut nll: f64 = 0.0;
    let mut ref_nll: f64 = 0.0;
    let mut count: u64 = 0;
    // KL accumulators: mean + max + a coarse histogram for a robust tail
    // percentile without holding every per-token value.
    let mut kl_sum: f64 = 0.0;
    let mut kl_max_seen: f64 = 0.0;
    // Log-spaced buckets in [2^-20, 2^4); index by floor(log2(kl))+20.
    const KL_BUCKETS: usize = 24;
    let mut kl_hist = [0u64; KL_BUCKETS + 1];
    let run_start = Instant::now();

    for c in 0..n_chunk {
        let start = c * n_ctx;
        let window = &all_tokens[start..start + n_ctx];

        let tw = Instant::now();
        let logits_all = chunk_logits(&mut pipeline, window, &dims)?;
        let ref_logits: Option<Vec<f32>> = match ref_pipeline.as_mut() {
            Some(rp) => Some(chunk_logits(rp, window, &dims)?),
            None => None,
        };

        // Score positions [first, n_ctx-1): predict window[pos+1].
        for pos in first..(n_ctx - 1) {
            let target = window[pos + 1] as usize;
            let row = &logits_all[pos * vocab_size..(pos + 1) * vocab_size];
            nll += -log_softmax_at(row, target);
            count += 1;

            if let Some(rl) = &ref_logits {
                let rrow = &rl[pos * vocab_size..(pos + 1) * vocab_size];
                ref_nll += -log_softmax_at(rrow, target);
                let kl = kl_ref_kaiju(rrow, row);
                kl_sum += kl;
                if kl > kl_max_seen {
                    kl_max_seen = kl;
                }
                let b = if kl <= 0.0 {
                    0
                } else {
                    let idx = (kl.log2().floor() as i64) + 20;
                    idx.clamp(0, KL_BUCKETS as i64) as usize
                };
                kl_hist[b] += 1;
            }
        }

        let ppl_running = (nll / count as f64).exp();
        if ref_logits.is_some() {
            println!(
                "[ppl] chunk {}/{}  {:.1}s/chunk  PPL={:.4} refPPL={:.4} meanKL={:.5} (count={})",
                c + 1,
                n_chunk,
                tw.elapsed().as_secs_f64(),
                ppl_running,
                (ref_nll / count as f64).exp(),
                kl_sum / count as f64,
                count
            );
        } else {
            println!(
                "[ppl] chunk {}/{}  {:.1}s/chunk  running PPL = {:.4}  (count={})",
                c + 1,
                n_chunk,
                tw.elapsed().as_secs_f64(),
                ppl_running,
                count
            );
        }
    }

    let mean_nll = nll / count as f64;
    let ppl = mean_nll.exp();
    println!("============================================================");
    println!(
        "[RESULT] KAIJU1 native ppl  ctx={}  chunks={}  scored_tokens={}",
        n_ctx, n_chunk, count
    );
    println!("[RESULT] mean_nll = {:.6}", mean_nll);
    println!("[RESULT] PPL = {:.4}", ppl);
    println!(
        "[RESULT] wall = {:.1}s  ({:.1}s/chunk)",
        run_start.elapsed().as_secs_f64(),
        run_start.elapsed().as_secs_f64() / n_chunk as f64
    );

    // ── Distributional gate verdict (only when a ref knot was supplied) ──
    if ref_knot_path.is_some() && count > 0 {
        let mean_kl = kl_sum / count as f64;
        let ref_ppl = (ref_nll / count as f64).exp();
        // p95 KL from the log-spaced histogram (upper bucket edge — conservative).
        let cut = ((count as f64) * 0.95).ceil() as u64;
        let mut acc = 0u64;
        let mut p95_bucket = KL_BUCKETS;
        for (b, &n) in kl_hist.iter().enumerate() {
            acc += n;
            if acc >= cut {
                p95_bucket = b;
                break;
            }
        }
        let p95_upper = if p95_bucket == 0 {
            0.0
        } else {
            2f64.powi(p95_bucket as i32 - 20 + 1)
        };
        println!("============================================================");
        println!(
            "[KLGATE] mean_kl={:.6} max_kl={:.6} p95_kl_le={:.6} ref_ppl={:.4} kaiju_ppl={:.4} ppl_ratio={:.4}",
            mean_kl,
            kl_max_seen,
            p95_upper,
            ref_ppl,
            ppl,
            ppl / ref_ppl
        );

        let mut fail = false;
        if let Some(kmax) = kl_max {
            if mean_kl > kmax {
                println!("[KLGATE] FAIL — mean_kl {mean_kl:.6} > --kl-max {kmax:.6}");
                fail = true;
            } else {
                println!("[KLGATE] PASS kl — mean_kl {mean_kl:.6} <= --kl-max {kmax:.6}");
            }
        }
        if let Some(slack) = ppl_slack {
            let bound = ref_ppl * (1.0 + slack);
            if ppl > bound {
                println!(
                    "[KLGATE] FAIL — kaiju_ppl {ppl:.4} > ref_ppl*(1+{slack}) = {bound:.4}"
                );
                fail = true;
            } else {
                println!(
                    "[KLGATE] PASS ppl — kaiju_ppl {ppl:.4} <= ref_ppl*(1+{slack}) = {bound:.4}"
                );
            }
        }
        if kl_max.is_none() && ppl_slack.is_none() {
            println!("[KLGATE] informational (no --kl-max / --ppl-slack threshold set)");
        }
        if fail {
            return Err("distributional gate FAILED".into());
        }
    }
    Ok(())
}
